13058	\begin{lemma}\leanok
13059	[The opens-preimage functor of a continuous map is final]
13060	  \label{lem:opensMap_final}
13061	  \lean{AlgebraicGeometry.opensMap_final}
13062	  \uses{lem:opensMap_structuredArrow_isFiltered}
13063	  For any continuous map \(\varphi : T \to T'\), the preimage functor
13064	  \(U \mapsto \varphi^{-1}(U)\), from open subsets of \(T'\) to open subsets of \(T\), is a
13065	  final functor.
13066	\end{lemma}
13067	\begin{proof}\leanok
13068	  \uses{lem:opensMap_structuredArrow_isFiltered}
13069	  A functor is final as soon as, for every object \(d\) of the target, the comma category of
13070	  maps from \(d\) into its image is connected; by
13071	  \cref{lem:opensMap_structuredArrow_isFiltered} these comma categories are filtered, and
13072	  filtered categories are connected.
13073	\end{proof}
