13075	\begin{lemma}\leanok
13076	[Pullback of the structure sheaf]
13077	  \label{lem:module_pullback_unit_iso}
13078	  \lean{AlgebraicGeometry.pullbackObjUnitToUnit_isIso_hom, AlgebraicGeometry.pullbackUnitIso}
13079	  \uses{lem:opensMap_final}
13080	  For any morphism of schemes \(g : Y \to X\), the canonical comparison morphism
13081	  \(g^*\mathcal{O}_X \to \mathcal{O}_Y\) of sheaves of \(\mathcal{O}_Y\)-modules is an
13082	  isomorphism.
13083	\end{lemma}
13084	\begin{proof}\leanok
13085	  \uses{lem:opensMap_final}
13086	  By the pullback--pushforward adjunction, morphisms \(g^*\mathcal{O}_X \to \mathcal{M}\)
13087	  correspond to morphisms \(\mathcal{O}_X \to g_*\mathcal{M}\), i.e.\ to global sections of
13088	  \(g_*\mathcal{M}\). Since the opens-preimage functor underlying \(g\) is final
13089	  (\cref{lem:opensMap_final}), global sections of \(g_*\mathcal{M}\) coincide with global
13090	  sections of \(\mathcal{M}\), which correspond to morphisms \(\mathcal{O}_Y \to \mathcal{M}\).
13091	  Thus \(g^*\mathcal{O}_X\) and \(\mathcal{O}_Y\) corepresent the same functor, and the
13092	  comparison morphism realizes this identification, hence is an isomorphism.
13093	\end{proof}
