13095	\begin{lemma}\leanok
13096	[Per-slice presentation of a pullback]
13097	  \label{lem:presentation_pullback_slice_of_over}
13098	  \lean{AlgebraicGeometry.presentationPullbackSliceOfOver}
13099	  \uses{lem:module_pullback_unit_iso}
13100	  Let \(g : Y \to X\) be a morphism of schemes, \(\mathcal{F}\) an \(\mathcal{O}_X\)-module,
13101	  and \(A \subseteq X\) an open subset over which \(\mathcal{F}\) admits a presentation
13102	  \(\bigoplus_{\iota}\mathcal{O} \to \bigoplus_{\sigma}\mathcal{O} \to \mathcal{F}|_A \to 0\).
13103	  Then the pullback \(g^*\mathcal{F}\) admits a presentation over the preimage open
13104	  \(W = g^{-1}(A)\).
13105	\end{lemma}
13106	\begin{proof}\leanok
13107	  \uses{lem:module_pullback_unit_iso, lem:isQuasicoherent_pullback_opens}
13108	  Let \(g_A : W \to A\) denote the restriction of \(g\), so that
13109	  \(\iota_W \circ g = g_A \circ \iota_A\) with \(\iota_A, \iota_W\) the open inclusions.
13110	  Pseudofunctoriality of the module pullback applied to this square identifies
13111	  \((g^*\mathcal{F})|_W \cong g_A^*(\mathcal{F}|_A)\). The functor \(g_A^*\) is a left
13112	  adjoint, hence preserves colimits, and it carries the structure sheaf to the structure
13113	  sheaf (\cref{lem:module_pullback_unit_iso}), hence free modules to free modules; applying it to
13114	  the given presentation of \(\mathcal{F}|_A\) therefore yields a presentation of
13115	  \(g_A^*(\mathcal{F}|_A) \cong (g^*\mathcal{F})|_W\). Carrying this presentation of the
13116	  restriction back to the slice over \(W\) is the same restrict--over bridge used in
13117	  \cref{lem:isQuasicoherent_pullback_opens}.
13118	\end{proof}
