13120	\begin{lemma}\leanok
13121	[Pullback preserves quasi-coherence (general morphism)]
13122	  \label{lem:pullback_isQuasicoherent_hom}
13123	  \lean{AlgebraicGeometry.pullback_isQuasicoherent_hom}
13124	  \uses{lem:presentation_pullback_slice_of_over}
13125	  % SOURCE: [Stacks Project], Modules, Tag 01BG (\texttt{lemma-pullback-quasi-coherent}).
13126	  \textit{Source: Stacks Project, Tag 01BG, \texttt{lemma-pullback-quasi-coherent}.}
13127	  Let \(g : Y \to X\) be a morphism of schemes and \(\mathcal{F}\) a quasi-coherent
13128	  \(\mathcal{O}_X\)-module. Then \(g^*\mathcal{F}\) is a quasi-coherent
13129	  \(\mathcal{O}_Y\)-module.
13130	\end{lemma}
13131	\begin{proof}\leanok
13132	  \uses{lem:presentation_pullback_slice_of_over}
13133	  Choose an open cover \(\{A_i\}\) of \(X\) over whose members \(\mathcal{F}\) admits
13134	  presentations. The preimages \(g^{-1}(A_i)\) cover \(Y\), and over each of them
13135	  \(g^*\mathcal{F}\) admits a presentation by
13136	  \cref{lem:presentation_pullback_slice_of_over}. Quasi-coherence is local on the base, so
13137	  \(g^*\mathcal{F}\) is quasi-coherent.
13138	\end{proof}
